from typing import Any, Optional

def parse_tool_result(raw: Any) -> Optional[dict]:
    """
    Parse a raw tool call result from an LLM into a structured dict.
    Returns None if the result is unusable.
    Used in an agent orchestration loop.
    """
    # LLMs sometimes return None for tool errors
    if raw is None:
        return None

    # String result: try JSON parsing
    if isinstance(raw, str):
        import json
        try:
            parsed = json.loads(raw)
        except json.JSONDecodeError:
            # Plain-text result — wrap in dict
            return {"text": raw, "type": "plain_text"}
        raw = parsed

    # Dict result: validate required fields
    if isinstance(raw, dict):
        if "error" in raw:
            return None  # Tool reported an error
        # Normalise numeric fields
        if "count" in raw:
            raw["count"] = int(raw["count"])  # might arrive as float or str
        if "score" in raw:
            raw["score"] = float(raw["score"])
        return raw

    # List result: wrap for uniform handling
    if isinstance(raw, list):
        return {"items": raw, "count": len(raw), "type": "list"}

    # Fallback: convert to string representation
    return {"value": str(raw), "type": type(raw).__name__}


# Usage
print(parse_tool_result(None))               # None
print(parse_tool_result('{"count": "5"}'))  # {'count': 5, 'type': ..., ...}
print(parse_tool_result([1, 2, 3]))          # {'items': [1, 2, 3], 'count': 3, ...}
print(parse_tool_result(42))                 # {'value': '42', 'type': 'int'}
